// Solution
function solve(query) {
    let rows = query.split('SELECT')[1].split('FROM')[0].split(',').map(x => x.trim());
    let uniqueRows = [...new Set(rows)];
    return uniqueRows.sort().join(',');
}

solutions.python:
class Solution:
    def solve(self):
        query = input()
        rows = query.split('SELECT')[1].split('FROM')[0].split(',').strip().split(',')
        unique_rows = list(set([x.strip() for x in rows]))
        return ','.join(sorted(unique_rows))
